def validate_user(data):
    required = ["name", "age", "email"]

    # Check required fields
    for field in required:
        if field not in data:
            raise ValueError(f"Missing required field: {field}")

    # Check types
    if not isinstance(data["name"], str):
        raise TypeError("name must be string")
    if not isinstance(data["age"], int):
        raise TypeError("age must be integer")
    if not isinstance(data["email"], str):
        raise TypeError("email must be string")

    return data

from pydantic import BaseModel
from pydantic import ConfigDict

# Default (permissive) — coerces '42' -> 42, 'true' -> True
class PermissiveModel(BaseModel):
    count: int
    active: bool
    score: float

# Strict — raises ValidationError for any type mismatch
class StrictModel(BaseModel):
    model_config = ConfigDict(strict=True)
    count: int
    active: bool
    score: float

# Test the difference
test_data = {"count": "42", "active": "true", "score": "3.14"}

permissive = PermissiveModel.model_validate(test_data)  # Works: count=42, active=True
print(f"Permissive: {permissive}")

try:
    strict = StrictModel.model_validate(test_data)  # Raises ValidationError
except Exception as e:
    print(f"Strict mode error: {e}")

# Recommended pattern: use permissive by default, validate semantic constraints separately
from pydantic import field_validator

class ProductReview(BaseModel):
    rating: int           # Coerces '4' -> 4
    sentiment: str

    @field_validator('rating')
    @classmethod
    def rating_in_range(cls, v: int) -> int:
        if not 1 <= v <= 5:
            raise ValueError(f'Rating must be 1-5, got {v}')
        return v
